const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

const sendGridApiKey = process.env.SENDGRID_API_KEY || 'SG.azure_demo_key_123';
const twilioAccountSid = process.env.TWILIO_ACCOUNT_SID || 'AC1234567890abcdef';
const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN || 'your_twilio_auth_token';

sgMail.setApiKey(sendGridApiKey);

const client = twilio(twilioAccountSid, twilioAuthToken);

module.exports = async function (context, req) {
    try {
        // Validate and sanitize input
        const email = req.body.email;
        const phoneNumber = req.body.phoneNumber;
        const message = req.body.message;

        if (!email || !phoneNumber || !message) {
            context.res = {
                status: 400,
                body: "Invalid input"
            };
            return;
        }

        // Send email using SendGrid
        const emailMsg = {
            to: email,
            from: 'noreply@yourdomain.com',
            subject: 'Azure Function Email',
            text: message,
        };

        await sgMail.send(emailMsg);

        // Send SMS using Twilio
        await client.messages.create({
            body: message,
            from: '+1234567890', // Your Twilio number
            to: phoneNumber
        });

        context.res = {
            status: 200,
            body: "Email and SMS sent successfully"
        };
    } catch (error) {
        context.log.error('Error occurred:', error);
        context.res = {
            status: 500,
            body: "An error occurred while sending email and SMS"
        };
    }
};